def compute_score():
    # Identify the references slide id
    slide_ids = set()
    for slide in ppt_diff.added_slides + [s2 for _, s2 in ppt_diff.modified_slides]:
        if slide.title and "references" in slide.title.lower():
            slide_ids.add(slide.slide_id)
    if not slide_ids:
        from pptx import Presentation

        try:
            pres = Presentation(modified_ppt_path)
            for i, slide in enumerate(pres.slides):
                for sh in slide.shapes:
                    if sh.has_text_frame and "references" in sh.text.lower():
                        slide_ids.add(slide.slide_id)
        except Exception:
            pass
    if not slide_ids:
        return "No references slide id found. Cannot check animations.", 0.0
    # Find all text elements on references slide(s)
    from pptx import Presentation

    pres = Presentation(modified_ppt_path)
    text_elements = []
    references_slide_numbers = []

    for i, slide in enumerate(pres.slides):
        if hasattr(slide, "slide_id") and str(slide.slide_id) in slide_ids:
            references_slide_numbers.append(i + 1)
            for sh in slide.shapes:
                if sh.has_text_frame and sh.text.strip():
                    text_elements.append(sh.text.strip().replace("\n", ''))
    # If no text found, fail
    if not text_elements:
        return "No text found on references slide to animate.", 0.0
    # For each text element, check if an appropriate animation was applied
    # We'll match by slide_id and try to match text (if available)
    animated_texts = []
    for anim in ppt_diff.added_animations + [
        a2 for _, a2 in ppt_diff.modified_animations
    ]:
        if anim.slide_id in slide_ids:
            if (
                anim.trigger == "click"
                and anim.effect_type.lower() == "fly_in_from_left"
            ):
                if anim.element_text is not None:
                    animated_texts.append(anim.element_text.strip())
    # Score: proportion of reference slide text that was animated correctly
    text_elements = set(text_elements)
    matched = set(animated_texts)

    # Ignore the page number.
    unmatched = set(text_elements) - matched - set({'34'})

    if not matched:
        return f"No references text was animated with Fly In from left.", 0.0
    if not unmatched:
        return "All references text correctly animated with Fly In from left.", 1.0
    partial = len(matched) / max(1, len(text_elements))
    return (
        f"Some references text not animated with Fly In from left: {unmatched}",
        partial,
    )

def compute_score():
    # Identify references slide ids
    slide_ids = set()
    for slide in ppt_diff.added_slides + [s2 for _, s2 in ppt_diff.modified_slides]:
        if slide.title and 'references' in slide.title.lower():
            slide_ids.add(slide.slide_id)
    # All added animations should be only on references slide
    extraneous = []
    for anim in ppt_diff.added_animations:
        if anim.slide_id not in slide_ids:
            extraneous.append(anim)
    if not extraneous:
        return "No unnecessary animations added to other slides.", 1.0
    return f"Found {len(extraneous)} unnecessary animations added.", 0.0
